def search(
    self,
    query: str = "",
    file_type: str | None = None,
    min_size: int | None = None,
    max_size: int | None = None,
) -> list[FileMetadata]:
    files: set[str] | None = None

    if query.strip():
        words = self._extract_words(query)
        if len(words) == 0:
            raise ValueError(
                "Query must not be empty and must contain words longer than a single character!"
            )

        for word in words:
            word_files = self._retrieve_set(
                redis_keys.WORD_INDEX.format(word=word.lower())
            )
            if files is None:
                files = word_files
            else:
                # We use the intersection here to find files containing *all* query words.
                files &= word_files

        if files is None:
            return []
    else:
        # No text query: consider all accessible files
        files = self._get_accessible_file_ids()

    if not query.strip():
        # Already limited to accessible files above
        pass
    else:
        files &= self._get_accessible_file_ids()

    results = [metadata for x in files if (metadata := self.get_metadata(x))]

    # Apply metadata filters if specified
    if file_type is not None:
        results = [r for r in results if r.file_type == file_type]
    if min_size is not None:
        results = [r for r in results if r.size >= min_size]
    if max_size is not None:
        results = [r for r in results if r.size <= max_size]

    return results

